// "name" adlı dəyişən yaradıram
let name = "Aysel";
console.log(name); // nəticə: Aysel

// Dəyişənin içindəkini dəyişirəm
name = "Kamran";
console.log(name); // nəticə: Kamran

// Blok scope nümunəsi
if (true) {
  let color = "blue";
  console.log(color); // nəticə: blue
}
// console.log(color); // Xəta: color is not defined, çünki blok xaricində işləmir

// Hoisting nümunəsi
// console.log(toy); // Xəta: Cannot access "toy" before initialization
let toy = "robot";
console.log(toy); // nəticə: robot

// let ilə təkrar elan etmək olmaz
let gadget = "phone";
// let gadget = "earphones"; // Xəta: gadget has already been declared

// Dəyəri dəyişə bilərsən
gadget = "earphones";
console.log(gadget); // nəticə: earphones

// const ilə dəyəri dəyişmək olmaz
const name = "Kamran";
// name = "Murad"; // Xəta: Assignment to constant variable

// Real həyat nümunəsi
let bag = "laptop";
console.log(bag); // nəticə: laptop

// Siyirmənin içindəkini dəyişirəm
bag = "book";
console.log(bag); // nəticə: book

// Blok scope ilə nümunə
if (true) {
  let item = "pen";
  console.log(item); // nəticə: pen
}
// console.log(item); // Xəta: item is not defined

