// Create a variable called "name" with "Aysel"
let name = "Aysel";
console.log(name); // Output: Aysel

// Change the variable's content
name = "Kamran";
console.log(name); // Output: Kamran

// Block scope example
if (true) {
  let color = "blue";
  console.log(color); // Output: blue
}
// console.log(color); // Error: color is not defined, because it’s not accessible outside the block

// Hoisting example
// console.log(toy); // Error: Cannot access "toy" before initialization
let toy = "robot";
console.log(toy); // Output: robot

// You can’t redeclare with let
let gadget = "phone";
// let gadget = "earphones"; // Error: gadget has already been declared

// You can change the value
gadget = "earphones";
console.log(gadget); // Output: earphones

// You can’t change const’s value
const name = "Kamran";
// name = "Murad"; // Error: Assignment to constant variable

// Real-life example
let bag = "laptop";
console.log(bag); // Output: laptop

// Change the drawer’s content
bag = "book";
console.log(bag); // Output: book

// Block scope example
if (true) {
  let item = "pen";
  console.log(item); // Output: pen
}
// console.log(item); // Error: item is not defined

