console.log(name); // Вывод: Кямран

// Пример блочной области видимости
if (true) {
  let color = "синий";
  console.log(color); // Вывод: синий
}
// console.log(color); // Ошибка: color не определён, так как недоступен вне блока

// Пример hoisting
// console.log(toy); // Ошибка: Cannot access "toy" before initialization
let toy = "робот";
console.log(toy); // Вывод: робот

// Нельзя повторно объявить с let
let gadget = "телефон";
// let gadget = "наушники"; // Ошибка: gadget уже объявлен

// Можно менять значение
gadget = "наушники";
console.log(gadget); // Вывод: наушники

// Нельзя изменить значение const
const name = "Кямран";
// name = "Мурад"; // Ошибка: Присвоение константе

// Пример из реальной жизни
